90	// UpsertHandset upserts a handset from the legacy equinoxdb/cron path (no versioning).
91	func (s storage) UpsertHandset(ctx context.Context, handset handsetdb.Handset) error {
92		m := bson.M{
93			"id": handset.ID,
94		}
95	
96		if handset.Name != "" {
97			m["name"] = handset.Name
98		}
99		if handset.RetailPrice != "" {
100			m["retailPrice"] = handset.RetailPrice
101		}
102		if handset.ContractPrice != "" {
103			m["contractPrice"] = handset.ContractPrice
104		}
105		if handset.ContractTerm != "" {
106			m["contractTerm"] = handset.ContractTerm
107		}
108		m["active"] = handset.Active
109		m["outOfStock"] = handset.OutOfStock
110	
111		_, err := s.handsetsCollection.
112			UpdateOne(ctx, bson.M{"id": handset.ID}, bson.M{"$set": m}, options.Update().SetUpsert(true))
113		if err != nil {
114			return fmt.Errorf("could not upsert handset: %w", err)
115		}
116		return nil
117	}
