119	// UpsertHandsetModel upserts a models.Handset with versioning support.
120	// When currentProperties.Version changes, the old properties are pushed into the versions array.
121	func (s storage) UpsertHandsetModel(ctx context.Context, handset models.Handset) error {
122		// Fetch the existing document to determine if currentProperties has changed
123		var existing models.Handset
124		err := s.handsetsCollection.FindOne(ctx, bson.M{"billID": handset.BillID}).Decode(&existing)
125		if err != nil && !errors.Is(err, mongo.ErrNoDocuments) {
126			return fmt.Errorf("could not fetch existing handset: %w", err)
127		}
128	
129		update := bson.M{}
130	
131		if err == nil {
132			// Document exists – push old currentProperties into versions if version changed
133			if existing.CurrentProperties.Version != "" && existing.CurrentProperties.Version != handset.CurrentProperties.Version {
134				update["$push"] = bson.M{"versions": existing.CurrentProperties}
135			}
136		}
137	
138		// Ensure newly inserted handsets have a stable UUID id.
139		update["$setOnInsert"] = bson.M{
140			"id": uuid.New(),
141		}
142	
143		update["$set"] = bson.M{
144			"billID":            handset.BillID,
145			"active":            handset.Active,
146			"currentProperties": handset.CurrentProperties,
147		}
148	
149		_, err = s.handsetsCollection.
150			UpdateOne(ctx, bson.M{"billID": handset.BillID}, update, options.Update().SetUpsert(true))
151		if err != nil {
152			return fmt.Errorf("could not upsert handset: %w", err)
153		}
154	
155		return nil
156	}
