158	func (s storage) GetHandsets(ctx context.Context, isInStock bool) ([]models.Handset, error) {
159		filter := bson.M{"active": true}
160		if isInStock {
161			filter["quantityInStock"] = bson.M{"$gt": 0}
162		}
163	
164		cur, err := s.handsetsCollection.Find(ctx, filter)
165		if err != nil {
166			return nil, fmt.Errorf("could not find handsets: %w", err)
167		}
168	
169		defer func(cur *mongo.Cursor, ctx context.Context) {
170			err := cur.Close(ctx)
171			if err != nil {
172				tlog.Error(ctx, "could not close cursor: %s", err.Error())
173			}
174		}(cur, ctx)
175	
176		var handsets []models.Handset
177		for cur.Next(ctx) {
178			var handset models.Handset
179			err := cur.Decode(&handset)
180			if err != nil {
181				return nil, fmt.Errorf("could not decode handset: %w", err)
182			}
183			handsets = append(handsets, handset)
184		}
185	
186		if err := cur.Err(); err != nil {
187			return nil, fmt.Errorf("error iterating over handsets: %w", err)
188		}
189	
190		return handsets, nil
191	}
