270	func expectedCurrentStatuses(status models.ContractStatus) []models.ContractStatus {
271		switch status {
272		case models.ContractStatusEligibilityApproved, models.ContractStatusDeclined:
273			return []models.ContractStatus{models.ContractStatusPendingEligibility}
274		case models.ContractStatusApproved:
275			return []models.ContractStatus{models.ContractStatusEligibilityApproved}
276		case models.ContractStatusHandsetOrdered:
