283	func (s storage) updateContractStatus(ctx context.Context, filter bson.M, status models.ContractStatus, currentStatuses ...models.ContractStatus) error {
284		if len(currentStatuses) == 1 {
285			filter["status"] = currentStatuses[0]
286		} else if len(currentStatuses) > 1 {
287			filter["status"] = bson.M{"$in": currentStatuses}
288		}
289		update := bson.M{
290			"$set": bson.M{
291				"status":    status,
292				"updatedAt": time.Now(),
293			},
294		}
295	
296		result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
297		if err != nil {
298			return fmt.Errorf("could not update contract status: %w", err)
299		}
300		if result.MatchedCount == 0 {
301			if len(currentStatuses) > 0 {
302				return terrors.ErrConflict
303			}
304			return terrors.ErrNotFound
305		}
306		return nil
307	}
