395	// FindAndUpdateExpiredContracts This will return list of processed contracts even if it errors
396	func (s storage) FindAndUpdateExpiredContracts(ctx context.Context) ([]models.Contract, error) {
397		now := s.nowFunc()
398		filter := bson.M{
399			"status":    models.ContractStatusHandsetOrdered,
400			"expiresAt": bson.M{"$lte": now},
401		}
402		update := bson.M{
403			"$set": bson.M{
404				"status":    models.ContractStatusExpired,
405				"updatedAt": now,
406			},
407		}
408		opts := options.FindOneAndUpdate().SetReturnDocument(options.After)
409	
410		var expired []models.Contract
411		for {
412			var contract models.Contract
413			err := s.contractsCollection.FindOneAndUpdate(ctx, filter, update, opts).Decode(&contract)
414			if errors.Is(err, mongo.ErrNoDocuments) {
415				break
416			}
417			if err != nil {
418				return expired, fmt.Errorf("could not expire contract: %w", err)
419			}
420			expired = append(expired, contract)
421		}
422	
423		return expired, nil
424	}
