58	func (c *Consumer) ConsumeMobileHandsetContractApproved(ctx context.Context, env *message.Envelope,
59		in *serviceevents.MobileHandsetContractApproved, ack func() error,
60	) error {
61		contractIDStr := in.GetContractId()
62		serviceID := in.GetServiceId()
63		customerID := in.GetCustomerId()
64		handsetID := in.GetHandsetId()
65	
66		contractID, err := uuid.Parse(contractIDStr)
67		if err != nil {
68			return fmt.Errorf("invalid contract_id %q: %w", contractIDStr, err)
69		}
70	
71		tlog.WithAttribute("contract_id", contractIDStr).
72			WithAttribute("service_id", serviceID).
73			WithAttribute("handset_id", handsetID).
74			Info(ctx, "processing handset contract approved event")
75	
76		// Look up contract — we need the request_id and bank details
77		contract, err := c.store.GetContractByID(ctx, contractID)
78		if err != nil {
79			return fmt.Errorf("failed to load contract %s: %w", contractIDStr, err)
80		}
81	
82		// Idempotency: if already approved or ordered, skip.
83		if contract.Status == models.ContractStatusApproved || contract.Status == models.ContractStatusHandsetOrdered {
84			tlog.WithAttribute("contract_id", contractIDStr).
85				WithAttribute("status", string(contract.Status)).
86				Info(ctx, "contract already processed, skipping")
87	
88			return ack()
89		}
90	
91		// Fetch customer details from account-gateway
92		accountResp, err := c.accountClient.GetAccount(ctx, &accountgateway.GetAccountRequest{
93			AccountId: customerID,
94		})
95		if err != nil {
96			return fmt.Errorf("failed to fetch account for customer %s: %w", customerID, err)
97		}
98	
99		// Build loan request
100		retailPriceAmount := in.GetRetailPrice().GetAmount()
101		if retailPriceAmount == "" {
102			return fmt.Errorf("retail price is required for approved handset contract %s", contractIDStr)
103		}
104		retailPrice, err := strconv.ParseFloat(retailPriceAmount, 32)
105		if err != nil {
106			return fmt.Errorf("failed to parse approved event retail price %q: %w", retailPriceAmount, err)
107		}
108	
109		contractMonths := in.GetContractMonths()
110		if contractMonths == "" {
111			return fmt.Errorf("contract months is required for approved handset contract %s", contractIDStr)
112		}
113		contractTerm, err := strconv.ParseInt(contractMonths, 10, 32)
114		if err != nil {
115			return fmt.Errorf("failed to parse approved event contract months %q: %w", contractMonths, err)
116		}
117		if contractTerm < 1 || contractTerm > math.MaxInt32 {
118			return fmt.Errorf("approved event contract months %q is outside supported range", contractMonths)
119		}
120	
121		loanReq := loanboxclient.CreateLoanRequest{
122			RequestID:         contract.RequestID,
123			AmountApproved:    float32(retailPrice),
124			TermMonths:        int32(contractTerm),
125			InterestRate:      loanboxclient.DefaultInterestRate,
126			LoanProduct:       loanboxclient.DefaultLoanProduct(),
127			BankAccountNumber: contract.BankAccountNumber,
128			BankTitle:         contract.BankTitle,
129		}
130	
131		// Enrich with customer details
132		if accountResp.GetAccount() != nil {
133			acct := accountResp.GetAccount()
134			if contact := acct.GetContactDetails(); contact != nil {
135				loanReq.Email = contact.GetEmail()
136				loanReq.Phone = contact.GetMobile()
137				parts := strings.Fields(contact.GetSalutation())
138				if len(parts) >= 2 {
139					loanReq.FirstName = parts[0]
140					loanReq.LastName = strings.Join(parts[1:], " ")
141				}
142			}
143			if customer := acct.GetCustomerDetails(); customer != nil && customer.GetDateOfBirth() != nil {
144				dob := customer.GetDateOfBirth().AsTime()
145				loanReq.DateOfBirth = &dob
146			}
147			if address := acct.GetCorrespondenceAddress(); address != nil {
148				loanReq.StreetAddress = strings.Join(address.GetFormattedLines(), ", ")
149				loanReq.CountryCode = "GB"
150			}
151		}
152	
153		tlog.WithAttribute("contract_id", contractIDStr).
154			WithAttribute("request_id", contract.RequestID).
155			WithAttribute("amount", fmt.Sprintf("%.2f", retailPrice)).
156			WithAttribute("term_months", strconv.FormatInt(contractTerm, 10)).
157			Info(ctx, "submitting loan request to Loanbox")
158	
159		loanResp, err := c.loanboxClient.CreateLoan(ctx, loanReq)
160		if err != nil {
161			return fmt.Errorf("loanbox loan creation failed for contract %s: %w", contractIDStr, err)
162		}
163	
164		// Store loan reference
165		loanRef := strconv.FormatInt(loanResp.LoanApplicationID, 10)
166		if err := c.store.UpdateContractLoanReference(ctx, contract.RequestID, loanRef); err != nil {
167			return fmt.Errorf("failed to store loan reference for contract %s: %w", contractIDStr, err)
168		}
169	
170		if err := c.store.UpdateContractStatus(ctx, contract.RequestID, models.ContractStatusApproved); err != nil {
171			if errors.Is(err, terrors.ErrConflict) {
172				tlog.WithAttribute("contract_id", contractIDStr).
173					Info(ctx, "contract status changed before approval update, skipping")
174	
175				return ack()
176			}
177	
178			return fmt.Errorf("failed to update contract %s to APPROVED: %w", contractIDStr, err)
179		}
180	
181		tlog.WithAttribute("contract_id", contractIDStr).
182			WithAttribute("loan_ref", loanRef).
183			Info(ctx, "loan created, contract approved")
184	
185		return ack()
186	}
