188	func (c *Consumer) ConsumeMobileHandsetOrdered(ctx context.Context, env *message.Envelope,
189		in *serviceevents.MobileHandsetOrdered, ack func() error,
190	) error {
191		contractIDStr := in.GetContractId()
192		if contractIDStr == "" {
193			return fmt.Errorf("contract_id is required for MobileHandsetOrdered %s", env.GetId())
194		}
195	
196		contractID, err := uuid.Parse(contractIDStr)
197		if err != nil {
198			return fmt.Errorf("invalid contract_id %q: %w", contractIDStr, err)
199		}
200	
201		contract, err := c.store.GetContractByID(ctx, contractID)
202		if err != nil {
203			return fmt.Errorf("failed to load contract %s: %w", contractIDStr, err)
204		}
205		if contract.Status == models.ContractStatusHandsetOrdered {
206			tlog.WithAttribute("contract_id", contractIDStr).
207				Info(ctx, "contract already HANDSET_ORDERED, skipping")
208	
209			return ack()
210		}
211		if contract.Status != models.ContractStatusApproved {
212			return fmt.Errorf("contract %s is not ready to mark HANDSET_ORDERED: status %s", contractIDStr, contract.Status)
213		}
214	
215		if err := c.store.UpdateContractStatusByID(ctx, contractID, models.ContractStatusHandsetOrdered); err != nil {
216			if errors.Is(err, terrors.ErrConflict) {
217				tlog.WithAttribute("contract_id", contractIDStr).
218					WithAttribute("status", string(contract.Status)).
219					Info(ctx, "contract is not approved, skipping handset ordered update")
220				return ack()
221			}
222	
223			return fmt.Errorf("failed to update contract %s as ordered: %w", contractIDStr, err)
224		}
225	
226		tlog.WithAttribute("contract_id", contractIDStr).
227			Info(ctx, "contract marked handset ordered")
228	
229		if contract.SignedAt != nil {
230			contractMonths, err := strconv.Atoi(contract.ContractMonths)
231			if err != nil {
232				return fmt.Errorf("invalid contract_months %q for contract %s: %w", contract.ContractMonths, contractIDStr, err)
233			}
234			expiresAt := contract.SignedAt.AddDate(0, contractMonths, 0)
235			if err := c.store.UpdateContractExpiresAt(ctx, contractID, expiresAt); err != nil {
236				return fmt.Errorf("failed to set expires_at for contract %s: %w", contractIDStr, err)
237			}
238		}
239	
240		return ack()
241	}
